def countdown(n):
    while n > 0:
        yield n
        n -= 1

for number in countdown(3):
    print(number)

def fibonacci():
    a, b = 0, 1
    while True:
        yield a
        a, b = b, a + b

fib = fibonacci()
for _ in range(5):
    print(next(fib))

coding_challenges.solution:
def read_numbers():
    for i in range(1, 11):
        yield i

def filter_even(gen):
    for num in gen:
        if num % 2 == 0:
            yield num

pipeline = filter_even(read_numbers())
for n in pipeline:
    print(n)
